{
  "summary": "CORA proposes a unified multilingual open question answering model that jointly performs cross-lingual dense passage retrieval and answer generation without relying on external translation modules. Through an iterative training procedure leveraging Wikipedia language links and synthetic data augmentation, CORA achieves state-of-the-art performance on multilingual QA benchmarks across many languages, including unseen ones.",
  "strengths": [
    {
      "point": "Unified approach to cross-lingual retrieval and generation",
      "evidence": "CORA integrates a multilingual dense passage retriever and an autoregressive answer generator into a single model that does not require external translation or language-specific retrieval components."
    },
    {
      "point": "Strong empirical performance on diverse multilingual benchmarks",
      "evidence": "CORA achieves large F1 gains (21.4 on XOR-TYDI QA and 4.9 on MKQA) across 26 languages, including 9 unseen during training, demonstrating effectiveness especially on low-resource languages."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior multilingual dense retrieval models",
      "evidence": "The paper lacks detailed architectural or training comparisons to existing multilingual dense retrievers such as mDPR variants, weakening the novelty claim."
    },
    {
      "point": "Limited ablation and justification of iterative training design and synthetic data impact",
      "evidence": "No ablation quantifies the isolated effect of synthetic data augmentation or sensitivity to iteration count, leaving unclear the necessity and contribution of these components."
    },
    {
      "point": "Evaluation metrics and baseline descriptions are incomplete",
      "evidence": "The evaluation focuses mainly on F1 without retrieval-specific metrics like recall@k or MRR, and baseline training data and model sizes are not fully described, raising concerns about fairness of comparisons."
    },
    {
      "point": "Reproducibility hindered by missing architectural and data processing details",
      "evidence": "Key details such as model sizes, hyperparameters, and exact mining criteria for cross-lingual data expansion are not sufficiently specified."
    },
    {
      "point": "Clarity issues regarding target language definition and cross-lingual retrieval mechanism",
      "evidence": "The paper does not clearly define how the target language is determined for answer generation nor how mDPR handles language mismatches at the embedding level."
    },
    {
      "point": "Limited discussion of limitations and generalizability",
      "evidence": "The paper does not address scalability to larger or noisier corpora, performance on languages with no Wikipedia presence, or applicability beyond Wikipedia-based QA."
    }
  ],
  "questions": [
    {
      "question": "How sensitive is CORA's performance to the number of iterative training cycles and could simpler training regimes achieve similar results?",
      "motivation": "Understanding this would clarify the necessity and efficiency of the proposed iterative training approach."
    },
    {
      "question": "How does CORA perform on languages with minimal or no Wikipedia presence, and can the approach generalize to other domains or document types?",
      "motivation": "This impacts the practical applicability and scalability of the model beyond the evaluated datasets."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
